  1→#!/usr/bin/env node
  2→
  3→/**
  4→ * sync-docs.js — Fetch docs from sequant-io/sequant and prepare for Starlight.
  5→ *
  6→ * Runs before `astro build` and `astro dev` to keep docs in sync.
  7→ * Falls back silently to committed local copies if the GitHub API is unreachable.
  8→ *
  9→ * Flags:
 10→ *   --force   Bypass the cache TTL and always fetch fresh docs
 11→ *
 12→ * Environment variables:
 13→ *   GITHUB_TOKEN — optional, raises API rate limit from 60 → 5 000 req/h
 14→ *   CI           — when truthy, always fetches (implies --force)
 15→ */
 16→
 17→import {
 18→  readFileSync,
 19→  writeFileSync,
 20→  mkdirSync,
 21→  rmSync,
 22→  existsSync,
 23→  readdirSync,
 24→  statSync,
 25→} from "node:fs";
 26→import { join, dirname, resolve } from "node:path";
 27→import { posix } from "node:path";
 28→import { fileURLToPath } from "node:url";
 29→
 30→// ---------------------------------------------------------------------------
 31→// Config
 32→// ---------------------------------------------------------------------------
 33→
 34→const __dirname = dirname(fileURLToPath(import.meta.url));
 35→const ROOT = resolve(__dirname, "..");
 36→const DOCS_DIR = join(ROOT, "src", "content", "docs", "docs");
 37→const CACHE_STAMP = join(ROOT, ".docs-last-sync");
 38→
 39→const REPO_OWNER = "sequant-io";
 40→const REPO_NAME = "sequant";
 41→const BRANCH = "main";
 42→const GITHUB_RAW = `https://raw.githubusercontent.com/${REPO_OWNER}/${REPO_NAME}/${BRANCH}`;
 43→const GITHUB_BLOB = `https://github.com/${REPO_OWNER}/${REPO_NAME}/blob/${BRANCH}`;
 44→const GITHUB_API = `https://api.github.com/repos/${REPO_OWNER}/${REPO_NAME}`;
 45→
 46→/** Prefixes excluded from the sync (relative to docs/). */
 47→const EXCLUDED_PREFIXES = ["internal/", "marketing/", "assets/", "examples/"];
 48→
 49→/** Individual files excluded from the sync (relative to docs/). */
 50→const EXCLUDED_FILES = ["README.md"];
 51→
 52→/** Files that live only in the landing repo — never overwritten by sync. */
 53→const LANDING_ONLY = ["index.md"];
 54→
 55→/**
 56→ * Path remapping: sequant repo path → landing site path.
 57→ * Resolves the quickstart path discrepancy (guides/ → getting-started/).
 58→ */
 59→const PATH_MAP = {
 60→  "guides/quickstart.md": "getting-started/quickstart.md",
 61→};
 62→
 63→const BATCH_SIZE = 10;
 64→
 65→/** Cache TTL in milliseconds (1 hour). */
 66→const CACHE_TTL_MS = 60 * 60 * 1000;
 67→
 68→// ---------------------------------------------------------------------------
 69→// Cache
 70→// ---------------------------------------------------------------------------
 71→
 72→const forceSync = process.argv.includes("--force") || Boolean(process.env.CI);
 73→
 74→function isCacheFresh() {
 75→  if (forceSync) return false;
 76→  if (!existsSync(CACHE_STAMP)) return false;
 77→  try {
 78→    const ts = Number(readFileSync(CACHE_STAMP, "utf-8").trim());
 79→    return Date.now() - ts < CACHE_TTL_MS;
 80→  } catch {
 81→    return false;
 82→  }
 83→}
 84→
 85→function writeCacheStamp() {
 86→  writeFileSync(CACHE_STAMP, String(Date.now()), "utf-8");
 87→}
 88→
 89→// ---------------------------------------------------------------------------
 90→// Helpers
 91→// ---------------------------------------------------------------------------
 92→
 93→function apiHeaders() {
 94→  const h = {
 95→    Accept: "application/vnd.github.v3+json",
 96→    "User-Agent": "Sequant-Landing-Sync",
 97→  };
 98→  const token = process.env.GITHUB_TOKEN;
 99→  if (token) h.Authorization = `token ${token}`;
100→  return h;
101→}
102→
103→/** Return all .md paths under docs/ in the sequant repo (relative to docs/). */
104→async function fetchFileTree() {
105→  const res = await fetch(`${GITHUB_API}/git/trees/${BRANCH}?recursive=1`, {
106→    headers: apiHeaders(),
107→  });
108→  if (!res.ok)
109→    throw new Error(`GitHub tree API ${res.status}: ${res.statusText}`);
110→  const data = await res.json();
111→  return data.tree
112→    .filter(
113→      (f) =>
114→        f.type === "blob" &&
115→        f.path.startsWith("docs/") &&
116→        f.path.endsWith(".md"),
117→    )
118→    .map((f) => f.path.replace(/^docs\//, ""));
119→}
120→
121→function shouldSync(relativePath) {
122→  if (EXCLUDED_FILES.includes(relativePath)) return false;
123→  return !EXCLUDED_PREFIXES.some((p) => relativePath.startsWith(p));
124→}
125→
126→/** Fetch raw markdown content from GitHub. */
127→async function fetchContent(relativePath) {
128→  const res = await fetch(`${GITHUB_RAW}/docs/${relativePath}`);
129→  if (!res.ok) throw new Error(`fetch ${relativePath}: ${res.status}`);
130→  return res.text();
131→}
132→
133→// ---------------------------------------------------------------------------
134→// Frontmatter
135→// ---------------------------------------------------------------------------
136→
137→/** Extract `# Title` from the first line (or first heading). */
138→function extractTitle(content) {
139→  const m = content.match(/^#\s+(.+)$/m);
140→  return m ? m[1].trim() : null;
141→}
142→
143→/** Grab the first real paragraph after the heading for `description`. */
144→function extractDescription(content) {
145→  let body = content
146→    .replace(/^---[\s\S]*?---\n*/, "") // strip existing frontmatter
147→    .replace(/^#\s+.+\n+/, "") // strip heading
148→    .replace(/^---\n+/, "") // strip hr
149→    .replace(/^>\s*.+\n*/gm, ""); // strip blockquotes
150→  const m = body.match(
151→    /^(\*{0,2}[^\n#>\-`\d].+?)(?:\n\n|\n#|\n>|\n-|\n\*|\n```|$)/s,
152→  );
153→  if (m) {
154→    return m[1]
155→      .replace(/\*{1,2}/g, "")
156→      .replace(/\n/g, " ")
157→      .replace(/\s+/g, " ")
158→      .trim()
159→      .slice(0, 200);
160→  }
161→  return "";
162→}
163→
164→/**
165→ * Inject Starlight-compatible YAML frontmatter and strip the leading `# heading`
166→ * so it isn't duplicated by Starlight's auto-rendered title.
167→ */
168→function injectFrontmatter(content, landingPath) {
169→  const title =
170→    extractTitle(content) || landingPath.replace(/\.md$/, "").split("/").pop();
171→  const desc = extractDescription(content);
172→
173→  const yaml = [
174→    "---",
175→    `title: "${title.replace(/"/g, '\\"')}"`,
176→    desc ? `description: "${desc.replace(/"/g, '\\"')}"` : null,
177→    "draft: false",
178→    "---",
179→  ]
180→    .filter(Boolean)
181→    .join("\n");
182→
183→  // Strip any existing frontmatter
184→  let body = content.replace(/^---[\s\S]*?---\n*/, "");
185→  // Strip the first `# …` heading (Starlight renders it from frontmatter)
186→  body = body.replace(/^#\s+.+\n+/, "");
187→
188→  return yaml + "\n\n" + body;
189→}
190→
191→// ---------------------------------------------------------------------------
192→// Link rewriting
193→// ---------------------------------------------------------------------------
194→
195→/**
196→ * Rewrite relative `.md` links to Starlight absolute paths.
197→ *
198→ * - Synced doc targets     → `/docs/<section>/<slug>`
199→ * - Excluded / out-of-tree → GitHub blob URL
200→ */
201→function rewriteLinks(content, fromFile, syncedLandingPaths) {
202→  // Pass 1: rewrite .md links
203→  let result = content.replace(
204→    /\[([^\]]*)\]\(([^)]*\.md(?:#[^)]*)?)\)/g,
205→    (match, text, href) => {
206→      if (href.startsWith("http://") || href.startsWith("https://"))
207→        return match;
208→
209→      const hashIdx = href.indexOf("#");
210→      const linkPath = hashIdx >= 0 ? href.slice(0, hashIdx) : href;
211→      const anchor = hashIdx >= 0 ? href.slice(hashIdx) : "";
212→
213→      const fromDir = posix.dirname(fromFile);
214→      const resolved = posix.normalize(posix.join(fromDir, linkPath));
215→
216→      // Link escapes above docs/ root → point at repo on GitHub
217→      if (resolved.startsWith("..")) {
218→        const repoPath = posix.normalize(posix.join("docs", fromDir, linkPath));
219→        return `[${text}](${GITHUB_BLOB}/${repoPath}${anchor})`;
220→      }
221→
222→      // Apply path remapping (e.g. guides/quickstart → getting-started/quickstart)
223→      const mapped = PATH_MAP[resolved] ?? resolved;
224→
225→      if (syncedLandingPaths.includes(mapped)) {
226→        const slug = "/docs/" + mapped.replace(/\.md$/, "");
227→        return `[${text}](${slug}${anchor})`;
228→      }
229→
230→      // Not a synced doc — link to GitHub
231→      return `[${text}](${GITHUB_BLOB}/docs/${resolved}${anchor})`;
232→    },
233→  );
234→
235→  // Pass 2: rewrite bare directory links (e.g. `stacks/`)
236→  result = result.replace(
237→    /\[([^\]]*)\]\((\.\/)?([\w-]+\/)\)/g,
238→    (match, text, _dotSlash, dir) => {
239→      const fromDir = posix.dirname(fromFile);
240→      const resolved = posix
241→        .normalize(posix.join(fromDir, dir))
242→        .replace(/\/$/, "");
243→      // Check if any synced doc lives under this directory
244→      if (syncedLandingPaths.some((p) => p.startsWith(resolved + "/"))) {
245→        return `[${text}](/docs/${resolved})`;
246→      }
247→      return match;
248→    },
249→  );
250→
251→  return result;
252→}
253→
254→// ---------------------------------------------------------------------------
255→// File operations
256→// ---------------------------------------------------------------------------
257→
258→/** Remove all synced content while preserving landing-only files. */
259→function cleanSyncedDocs() {
260→  if (!existsSync(DOCS_DIR)) return;
261→  for (const entry of readdirSync(DOCS_DIR, { withFileTypes: true })) {
262→    if (LANDING_ONLY.includes(entry.name)) continue;
263→    rmSync(join(DOCS_DIR, entry.name), { recursive: true, force: true });
264→  }
265→}
266→
267→// ---------------------------------------------------------------------------
268→// Main
269→// ---------------------------------------------------------------------------
270→
271→async function syncDocs() {
272→  // Check cache before hitting the network
273→  if (isCacheFresh()) {
274→    console.log(
275→      "Docs cache is fresh (< 1 h), skipping sync. Use --force to override.",
276→    );
277→    return;
278→  }
279→
280→  console.log("Syncing docs from sequant-io/sequant…");
281→
282→  try {
283→    // 1. Discover files
284→    const allFiles = await fetchFileTree();
285→    const toSync = allFiles.filter(shouldSync);
286→    console.log(`  Found ${toSync.length} docs to sync`);
287→
288→    // Landing-side paths after remapping (used for link resolution)
289→    const syncedLandingPaths = toSync.map((f) => PATH_MAP[f] ?? f);
290→
291→    // 2. Fetch contents (in parallel batches)
292→    const docs = [];
293→    for (let i = 0; i < toSync.length; i += BATCH_SIZE) {
294→      const batch = toSync.slice(i, i + BATCH_SIZE);
295→      const results = await Promise.all(
296→        batch.map(async (file) => ({
297→          file,
298→          content: await fetchContent(file),
299→        })),
300→      );
301→      docs.push(...results);
302→    }
303→
304→    // 3. Clean previous synced docs (keep landing-only files)
305→    cleanSyncedDocs();
306→
307→    // 4. Process & write
308→    for (const { file, content } of docs) {
309→      const landingPath = PATH_MAP[file] ?? file;
310→      const rewritten = rewriteLinks(content, file, syncedLandingPaths);
311→      const final = injectFrontmatter(rewritten, landingPath);
312→
313→      const outPath = join(DOCS_DIR, landingPath);
314→      mkdirSync(dirname(outPath), { recursive: true });
315→      writeFileSync(outPath, final, "utf-8");
316→    }
317→
318→    // 5. Update cache timestamp
319→    writeCacheStamp();
320→
321→    console.log(`  Synced ${docs.length} docs successfully`);
322→  } catch (err) {
323→    const hasLocalDocs =
324→      existsSync(DOCS_DIR) &&
325→      readdirSync(DOCS_DIR).some((f) => !LANDING_ONLY.includes(f));
326→
327→    if (hasLocalDocs) {
328→      console.warn(`  Sync failed (${err.message}), using existing local docs`);
329→    } else {
330→      console.error(
331→        `  Sync failed and no local docs available: ${err.message}`,
332→      );
333→      console.error("  Set GITHUB_TOKEN env var for higher rate limits");
334→      process.exit(1);
335→    }
336→  }
337→}
338→
339→syncDocs();
340→

