#!/usr/bin/env node

/**
 * sync-docs.js — Fetch docs from sequant-io/sequant and prepare for Starlight.
 *
 * Runs before `astro build` and `astro dev` to keep docs in sync.
 * Falls back silently to committed local copies if the GitHub API is unreachable.
 *
 * Flags:
 *   --force   Bypass the cache TTL and always fetch fresh docs
 *
 * Environment variables:
 *   GITHUB_TOKEN — optional, raises API rate limit from 60 → 5 000 req/h
 *   CI           — when truthy, always fetches (implies --force)
 */

import {
  readFileSync,
  writeFileSync,
  mkdirSync,
  rmSync,
  existsSync,
  readdirSync,
  statSync,
} from "node:fs";
import { join, dirname, resolve } from "node:path";
import { posix } from "node:path";
import { fileURLToPath } from "node:url";

// ---------------------------------------------------------------------------
// Config
// ---------------------------------------------------------------------------

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, "..");
const DOCS_DIR = join(ROOT, "src", "content", "docs", "docs");
const CACHE_STAMP = join(ROOT, ".docs-last-sync");

const REPO_OWNER = "sequant-io";
const REPO_NAME = "sequant";
const BRANCH = "main";
const GITHUB_RAW = `https://raw.githubusercontent.com/${REPO_OWNER}/${REPO_NAME}/${BRANCH}`;
const GITHUB_BLOB = `https://github.com/${REPO_OWNER}/${REPO_NAME}/blob/${BRANCH}`;
const GITHUB_API = `https://api.github.com/repos/${REPO_OWNER}/${REPO_NAME}`;

/** Prefixes excluded from the sync (relative to docs/). */
const EXCLUDED_PREFIXES = ["internal/", "marketing/", "assets/", "examples/"];

/** Individual files excluded from the sync (relative to docs/). */
const EXCLUDED_FILES = ["README.md"];

