// @ts-check
import { defineConfig } from 'astro/config';
import starlight from '@astrojs/starlight';
import sitemap from '@astrojs/sitemap';
import starlightLlmsTxt from 'starlight-llms-txt';
import tailwindcss from '@tailwindcss/vite';

// https://astro.build/config
export default defineConfig({
  site: 'https://sequant.io',
  integrations: [
    sitemap(),
    starlight({
      favicon: '/icon2.png',
      disable404Route: true,
      plugins: [
        starlightLlmsTxt({
          projectName: 'Sequant',
          description:
            'Open-source CLI and TypeScript library for AI-powered software development workflows. Provides structured pipelines for specification, execution, testing, and quality assurance using large language models.',
        }),
      ],
      title: 'Sequant Docs',
      logo: {
        light: './src/assets/docs-logo-light.svg',
        dark: './src/assets/docs-logo-dark.svg',
        replacesTitle: true,
      },
      social: [
        { icon: 'github', label: 'GitHub', href: 'https://github.com/sequant-io/sequant' },
        { icon: 'external', label: 'Sequant', href: '/' },
      ],
      head: [
        // Preconnect to Google Fonts for faster loading
        { tag: 'link', attrs: { rel: 'preconnect', href: 'https://fonts.googleapis.com' } },
        { tag: 'link', attrs: { rel: 'preconnect', href: 'https://fonts.gstatic.com', crossorigin: true } },
        {
          tag: 'link',
          attrs: {
            rel: 'stylesheet',
            href: 'https://fonts.googleapis.com/css2?family=Roboto:wght@300;400;500&family=Roboto+Mono:wght@400;500&display=swap',
          },
        },
        // Sync landing page theme → Starlight (runs before ThemeProvider)
        {
          tag: 'script',
          content: `(function(){var s=localStorage.getItem('sequant-theme');if(s==='light'||s==='dark')localStorage.setItem('starlight-theme',s);new MutationObserver(function(m){m.forEach(function(r){if(r.attributeName==='data-theme'){var t=document.documentElement.dataset.theme;if(t==='light'||t==='dark')localStorage.setItem('sequant-theme',t)}})}).observe(document.documentElement,{attributes:true,attributeFilter:['data-theme']})})();`,
        },
      ],
      customCss: ['./src/styles/starlight-custom.css'],
      components: {
        Head: './src/components/starlight/Head.astro',
      },
      sidebar: [
        {
          label: 'Getting Started',
          items: [
            { label: 'Installation', slug: 'docs/getting-started/installation' },
            { label: 'Prerequisites', slug: 'docs/getting-started/prerequisites' },
            { label: 'Quickstart', slug: 'docs/getting-started/quickstart' },
            { label: 'First Workflow', slug: 'docs/getting-started/first-workflow' },
          ],
        },
