/**
 * Starlight Custom CSS — Matches landing page design system
 *
 * Overrides Starlight's CSS custom properties to match the
 * tokens.css design system from the landing page.
 */

/* Fonts loaded via <link> tags in astro.config.mjs head config
   to avoid render-blocking @import */

/* ================================================
   LIGHT MODE (default)
   ================================================ */
:root {
  /* Typography */
  --sl-font: 'Roboto', -apple-system, BlinkMacSystemFont, sans-serif;
  --sl-font-mono: 'Roboto Mono', ui-monospace, SFMono-Regular, monospace;

  /* Brand colors — WCAG AA compliant */
  --sl-color-accent-low: #FFE0C8;
  --sl-color-accent: #B35000;   /* 5.16:1 vs white — matches --color-primary */
  --sl-color-accent-high: #B54E00;

  /* Gray scale — Starlight semantic convention (inverted):
     white = foreground extreme, black = background extreme.
     Values from landing-page tokens.css light mode. */
  --sl-color-white: #191919;       /* t-tile-text — strongest heading */
  --sl-color-gray-1: #333333;      /* t-text — body text */
  --sl-color-gray-2: #555555;      /* t-text-faint */
  --sl-color-gray-3: #999999;      /* t-text-muted */
  --sl-color-gray-4: #D4D4D4;      /* light border */
  --sl-color-gray-5: #EFEFEF;      /* t-surface-hover */
  --sl-color-gray-6: #F8F8F8;      /* t-surface-alt */
  --sl-color-black: #FFFFFF;        /* t-surface */

  /* Background — from tokens.css */
  --sl-color-bg: #FFFFFF;           /* t-surface */
  --sl-color-bg-nav: #F8F8F8;      /* t-surface-alt */
  --sl-color-bg-sidebar: #F8F8F8;  /* t-surface-alt */
  --sl-color-bg-inline-code: #EFEFEF; /* t-surface-hover */

  /* Text — from tokens.css */
  --sl-color-text: #666666;         /* t-text-secondary (body copy) */
  --sl-color-text-accent: var(--sl-color-accent-high);

  /* Hairline */
  --sl-color-hairline: #D4D4D4;
  --sl-color-hairline-light: #EFEFEF;
  --sl-color-hairline-shade: #999999;

  /* Badge colors */
  --sl-color-green-low: #D9EACD;
  --sl-color-green: #6B9B5E;
  --sl-color-green-high: #98C997;
}

/* ================================================
   DARK MODE
   ================================================ */
:root[data-theme='dark'] {
  /* Gray scale — values from tokens.css dark mode */
  --sl-color-white: #F4F4F5;       /* t-text / t-tile-text */
  --sl-color-gray-1: #D4D4D8;      /* t-text-secondary */
  --sl-color-gray-2: #A1A1AA;      /* t-text-faint */
  --sl-color-gray-3: #71717a;      /* t-text-muted */
  --sl-color-gray-4: #52525b;
  --sl-color-gray-5: #2a2a2e;
  --sl-color-gray-6: #1f1f23;
  --sl-color-black: #0f0f11;       /* t-surface */

  /* Background — from tokens.css */
  --sl-color-bg: #0f0f11;          /* t-surface */
  --sl-color-bg-nav: #141416;      /* t-surface-alt */
  --sl-color-bg-sidebar: #141416;  /* t-surface-alt */
  --sl-color-bg-inline-code: #1f1f23; /* t-surface-hover */

  /* Text — from tokens.css */
  --sl-color-text: #A1A1AA;        /* t-text-faint (body copy) */
  --sl-color-text-accent: var(--sl-color-accent-high);

  /* Hairline */
  --sl-color-hairline: #2a2a2e;    /* t-border */
  --sl-color-hairline-light: #1f1f23;
  --sl-color-hairline-shade: #3f3f46;

  /* Badge colors for dark */
  --sl-color-green-low: #1a2e19;
  --sl-color-green: #6B9B5E;
  --sl-color-green-high: #98C997;
}

/* ================================================
   TYPOGRAPHY ADJUSTMENTS
   ================================================ */

/* Match landing page heading styles */
h1, h2, h3, h4, h5, h6 {
  font-weight: 500;
  letter-spacing: -0.02em;
}

/* Body text */
body {
  font-weight: 400;
  line-height: 1.6;
}

/* Code blocks */
code {
  font-family: var(--sl-font-mono);
  font-size: 0.875em;
}

/* ================================================
   SIDEBAR CUSTOMIZATION
   ================================================ */

/* Sidebar link hover - use accent color */
.sidebar-content a:hover {
  color: var(--sl-color-accent);
}

/* Active sidebar link — keep Starlight's default inverted text color
   so it contrasts with the accent background pill */
[aria-current='page'],
[aria-current='page']:hover {
  font-weight: 600;
}

/* ================================================
   HEADER CUSTOMIZATION
   ================================================ */

/* Site title in header */
.site-title {
  font-weight: 500;
  letter-spacing: -0.01em;
}

/* Header nav links */
header nav a {
  font-weight: 500;
  font-size: 0.875rem;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

/* ================================================
   LINK STYLING
   ================================================ */

/* Content links use brand orange (contrast-safe) */
.sl-markdown-content a {
  color: var(--sl-color-text-accent);
  text-decoration: underline;
  text-underline-offset: 0.15em;
  text-decoration-thickness: 1px;
}

.sl-markdown-content a:hover {
  color: var(--sl-color-text-accent);
  text-decoration-thickness: 2px;
}

/* ================================================
   TABLE STYLING
   ================================================ */

/* Tables match landing page style */
table {
  border-collapse: collapse;
  width: 100%;
}

th {
  font-weight: 500;
  text-align: left;
  border-bottom: 2px solid var(--sl-color-hairline);
}

td {
  border-bottom: 1px solid var(--sl-color-hairline-light);
}

th, td {
  padding: 0.75rem 1rem;
}

/* ================================================
   CODE BLOCK STYLING
   ================================================ */

/* Code block background */
pre {
  background: var(--sl-color-bg-inline-code) !important;
  border: 1px solid var(--sl-color-hairline-light);
  border-radius: 8px;
}

/* Inline code */
:not(pre) > code {
  background: var(--sl-color-bg-inline-code);
  padding: 0.125em 0.375em;
  border-radius: 4px;
  font-size: 0.9em;
}

/* ================================================
   CALLOUT / ASIDE STYLING
   ================================================ */

/* Note/tip/caution boxes */
.starlight-aside {
  border-radius: 8px;
  border-left-width: 4px;
}

/* ================================================
   SEARCH STYLING
   ================================================ */

/* Search modal */
dialog.pagefind-ui {
  border-radius: 12px;
}

/* ================================================
   BUTTON STYLING (for any CTAs)
   ================================================ */

/* Primary button style */
.sl-link-button[data-variant='primary'] {
  background: var(--sl-color-accent);
  color: white;
  border-radius: 78px;
  font-weight: 500;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  padding: 0.75rem 1.5rem;
  transition: background 200ms ease;
}

.sl-link-button[data-variant='primary']:hover {
  background: var(--sl-color-accent-high);
}

/* ================================================
   FOOTER / BACK TO LANDING LINK
   ================================================ */

/* Add visual separation for footer */
footer {
  border-top: 1px solid var(--sl-color-hairline);
  margin-top: 3rem;
  padding-top: 2rem;
}

/* ================================================
   RESPONSIVE ADJUSTMENTS
   ================================================ */

@media (max-width: 768px) {
  /* Smaller text on mobile */
  :root {
    --sl-text-base: 1rem;
  }
}

/* ================================================
   MOTION / TRANSITIONS
   ================================================ */

/* Smooth transitions for interactive elements */
a, button, .sidebar-content a {
  transition: color 200ms ease, background 200ms ease;
}

/* Respect reduced motion preference */
@media (prefers-reduced-motion: reduce) {
  a, button, .sidebar-content a {
    transition: none;
  }
}

