<style>
  /* ── Pipeline diagram ── */
  .wi-pipeline {
    padding: 0 var(--side-spacing);
    margin-bottom: 3rem;
  }

  .wi-pipeline-flow {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0;
  }

  @media (min-width: 960px) {
    .wi-pipeline-flow {
      flex-direction: row;
      align-items: flex-start;
      justify-content: center;
      gap: 0;
    }
  }

  /* ── Steps ── */
  .wi-step {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
    position: relative;
  }

  .wi-step-desc {
    font-size: var(--font-size-sm);
    color: var(--t-text-muted);
    line-height: 1.5;
    max-width: 16ch;
    margin-top: 0.35rem;
  }

  /* ── Command Tiles ── */
  .wi-cmd-tile {
    aspect-ratio: 1;
    width: clamp(100px, 10vw, 130px);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    border-radius: 0.75rem;
    margin-bottom: 0.625rem;
  }

  .wi-cmd-tile--peach {
    background: #FFE0C8;
    border: 2px solid #FF8012;
  }

  .wi-cmd-tile--green {
    background: #D9EACD;
    border: 2px solid #6B9B5E;
  }

  .wi-cmd-tile--orange {
    background: #FF8012;
    border: 2px solid #FFE0C8;
  }

  .wi-cmd-tile--loop {
    background: rgba(255, 128, 18, 0.08);
    border: 2px solid rgba(255, 128, 18, 0.35);
    gap: 0.25rem;
  }

  .wi-cmd-tile--loop svg {
    color: var(--color-primary);  /* WCAG AA compliant */
    flex-shrink: 0;
  }

  .wi-cmd-tile--loop .wi-cmd-tile-command {
    color: var(--color-primary);  /* WCAG AA compliant */
  }

  .wi-cmd-tile--loop .wi-cmd-tile-fn {
    color: var(--color-primary);  /* WCAG AA compliant */
  }

  .wi-cmd-tile-command {
    font-family: var(--font-mono, 'Roboto Mono', monospace);
    font-size: clamp(1.15rem, 1.5vw, 1.5rem);
    font-weight: var(--font-weight-medium);
    letter-spacing: -0.02em;
    line-height: 1;
    color: var(--t-text);
  }

  .wi-cmd-tile--orange .wi-cmd-tile-command {
    color: var(--t-tile-text);
  }

  .wi-cmd-tile-fn {
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-medium);
    line-height: 1;
    color: var(--t-text);
  }

  .wi-cmd-tile--orange .wi-cmd-tile-fn {
    color: var(--t-tile-text);
  }

  /* ── Endpoint containers (Issue & Merge) ── */
  .wi-endpoint {
    width: clamp(100px, 10vw, 130px);
    aspect-ratio: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 0.375rem;
    border-radius: 0.75rem;
    margin-bottom: 0.625rem;
    background: var(--t-surface-alt);
    border: 2px solid var(--t-border);
  }

  .wi-endpoint-icon {
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--t-text);
  }

  .wi-endpoint-label {
    font-size: var(--font-size-xs);
    font-weight: var(--font-weight-medium);
    color: var(--t-text);
    line-height: 1.2;
  }

  .wi-endpoint-sublabel {
    font-size: var(--font-size-xs);
    color: var(--t-text-muted);
    line-height: 1;
  }

  .wi-endpoint--success {
    background: rgba(217, 234, 205, 0.3);
    border-color: rgba(107, 155, 94, 0.5);
  }

  .wi-endpoint--success .wi-endpoint-icon {
    color: #4a7a3e;
  }

  .wi-endpoint--success .wi-endpoint-label {
    color: #4a7a3e;
  }

  /* ── Connectors with gradient paths + chevrons ── */
  .wi-connector {
    position: relative;
    width: clamp(40px, 5vw, 64px);
    height: 40px;
    flex-shrink: 0;
  }

  .wi-connector svg {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    overflow: visible;
  }

  .wi-connector-path {
    fill: none;
    stroke-width: 2.5;
    stroke-linecap: round;
    opacity: 0.45;
  }

  .wi-connector-dash {
    fill: none;
    stroke-width: 2;
    stroke-linecap: round;
    stroke-dasharray: 3 10;
    opacity: 0.18;
    animation: wi-dash-flow 2.5s linear infinite;
    animation-play-state: paused;
  }

  :global(.wi-pipeline--running) .wi-connector-dash {
    animation-play-state: running;
  }

  @keyframes wi-dash-flow {
    to { stroke-dashoffset: -26; }
  }

  /* ── Chevrons ── */
  .wi-chevron-container {
    position: absolute;
    inset: 0;
    pointer-events: none;
  }

  .wi-chevron {
    position: absolute;
    width: 7px;
    height: 7px;
    top: 0;
    left: 0;
    opacity: 0;
    offset-path: path('M 0 20 C 14 8, 50 32, 64 20');
    offset-rotate: auto;
    animation: wi-chevron-travel 2s linear infinite;
    animation-play-state: paused;
  }

  :global(.wi-pipeline--running) .wi-chevron {
    animation-play-state: running;
  }

  .wi-chevron::before {
    content: '';
    position: absolute;
    inset: 0;
    border-right: 2.5px solid var(--chevron-color, #FF8012);
    border-top: 2.5px solid var(--chevron-color, #FF8012);
    transform: rotate(-45deg) scale(0.7);
    border-radius: 0 2px 0 0;
  }

  /* Chevron colors per connector */
  .wi-connector--1 .wi-chevron { --chevron-color: #FFB77A; }
  .wi-connector--2 .wi-chevron { --chevron-color: #6B9B5E; }
  .wi-connector--3 .wi-chevron { --chevron-color: #FF8012; }
  .wi-connector--4 .wi-chevron { --chevron-color: #FFB77A; }
  .wi-connector--5 .wi-chevron { --chevron-color: #6B9B5E; }

  @keyframes wi-chevron-travel {
    0%   { offset-distance: 0%;   opacity: 0; }
    12%  { opacity: 0.9; }
    80%  { opacity: 0.9; }
    100% { offset-distance: 100%; opacity: 0; }
  }

  /* Stagger: 3 chevrons evenly distributed across 2s cycle (2/3 ≈ 0.667s) */
  .wi-chevron:nth-child(1) { animation-delay: 0s; }
  .wi-chevron:nth-child(2) { animation-delay: 0.667s; }
  .wi-chevron:nth-child(3) { animation-delay: 1.333s; }

  /* Cascade: each connector starts 0.3s later */
  .wi-connector--2 .wi-chevron:nth-child(1) { animation-delay: 0.3s; }
  .wi-connector--2 .wi-chevron:nth-child(2) { animation-delay: 0.967s; }
  .wi-connector--2 .wi-chevron:nth-child(3) { animation-delay: 1.633s; }

  .wi-connector--3 .wi-chevron:nth-child(1) { animation-delay: 0.6s; }
  .wi-connector--3 .wi-chevron:nth-child(2) { animation-delay: 1.267s; }
  .wi-connector--3 .wi-chevron:nth-child(3) { animation-delay: 1.933s; }

  .wi-connector--4 .wi-chevron:nth-child(1) { animation-delay: 0.9s; }
  .wi-connector--4 .wi-chevron:nth-child(2) { animation-delay: 1.567s; }
  .wi-connector--4 .wi-chevron:nth-child(3) { animation-delay: 2.233s; }

  .wi-connector--5 .wi-chevron:nth-child(1) { animation-delay: 1.2s; }
  .wi-connector--5 .wi-chevron:nth-child(2) { animation-delay: 1.867s; }
  .wi-connector--5 .wi-chevron:nth-child(3) { animation-delay: 2.533s; }

  /* ── Mobile: vertical flow ── */
  @media (max-width: 959px) {
    .wi-pipeline-flow {
      gap: 0.5rem;
    }

    .wi-step {
      padding: 0;
    }

    .wi-connector {
      transform: rotate(90deg);
      width: 48px;
      height: 40px;
      margin: 0;
      padding: 0;
    }

    /* Scale offset-path to match 48px container width (desktop path
       is 64px). Only X coords scale by 48/64 = 0.75; Y stays at 40px. */
    .wi-chevron {
      offset-path: path('M 0 20 C 10.5 8, 37.5 32, 48 20');
      offset-rotate: 0deg;
    }

    /* Mobile tiles: rectangular, not square — saves vertical space */
    .wi-cmd-tile {
      width: clamp(140px, 42vw, 170px);
      aspect-ratio: auto;
      padding: 1rem 0.75rem;
      margin-bottom: 0.25rem;
    }

    .wi-endpoint {
      width: clamp(140px, 42vw, 170px);
      aspect-ratio: auto;
      padding: 0.75rem 0.5rem;
      margin-bottom: 0.25rem;
    }

    .wi-cmd-tile-command {
      font-size: 1.35rem;
    }

    .wi-step-desc {
      max-width: 22ch;
      font-size: var(--font-size-xs);
    }

    /* Extra breathing room beneath worktree step descriptions
       to match the outer step spacing */
    .wi-worktree .wi-step-desc {
      margin-bottom: 0.5rem;
    }

    /* Match worktree internal gap to pipeline-flow gap */
    .wi-worktree {
      padding: 1.25rem 1rem 1rem;
      gap: 0.5rem;
    }
  }

  /* ── Desktop layout ── */
  @media (min-width: 960px) {
    .wi-connector {
      align-self: flex-start;
    }

    .wi-step {
      width: clamp(100px, 10vw, 130px);
    }

    .wi-step--issue,
    .wi-step--spec,
    .wi-step--merge {
      margin-top: 2.5rem;
    }

    /* Outer connectors: tile center at 2.5rem + 60px = 100px.
       Connector 40px tall → top = 100-20 = 80px = 5rem */
    .wi-pipeline-flow > .wi-connector {
      margin-top: 5rem;
    }

    /* Inner worktree connectors: tile center at 60px from content start.
       Connector top = 60-20 = 40px = 2.5rem */
    .wi-worktree .wi-connector {
      margin-top: 2.5rem;
    }
  }

  /* ── Worktree boundary ── */
  .wi-worktree {
    border: none;
    border-radius: 1.25rem;
    padding: 2rem;
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0;
    background:
      linear-gradient(
        135deg,
        rgba(217, 234, 205, 0.15) 0%,
        rgba(255, 224, 200, 0.1) 100%
      );
    box-shadow:
      0 0 0 1px rgba(107, 155, 94, 0.08),
      0 4px 24px -4px rgba(0, 0, 0, 0.06);
  }

  .wi-worktree-border {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    z-index: 0;
  }

  .wi-worktree-border rect {
    animation: wi-dash-march 12s linear infinite;
    animation-play-state: paused;
  }

  :global(.wi-pipeline--running) .wi-worktree-border rect {
    animation-play-state: running;
  }

  @keyframes wi-dash-march {
    to { stroke-dashoffset: -140; }
  }

  .wi-worktree-label {
    position: absolute;
    top: -0.6875rem;
    left: 1.5rem;
    z-index: 1;
    font-size: var(--font-size-xs);
    font-weight: var(--font-weight-medium);
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: #4a7a3e;
    background: var(--t-surface);
    padding: 0.125rem 0.625rem;
    border-radius: 0.25rem;
    border: 1px solid rgba(107, 155, 94, 0.25);
  }

  @media (min-width: 960px) {
    .wi-worktree {
      flex-direction: row;
      align-items: flex-start;
      padding: 2rem;
      gap: 0;
    }
  }

  /* ── Dark mode ── */
  :global(:root.dark-mode) .wi-cmd-tile--peach {
    background: rgba(255, 224, 200, 0.12);
    border-color: #FF8012;
  }

  :global(:root.dark-mode) .wi-cmd-tile--green {
    background: rgba(217, 234, 205, 0.1);
    border-color: #6B9B5E;
  }

  :global(:root.dark-mode) .wi-cmd-tile--orange {
    background: rgba(255, 128, 18, 0.85);
    border-color: #FFE0C8;
  }

  /* Orange tile keeps dark text even in dark mode (bright background) */
  :global(:root.dark-mode) .wi-cmd-tile--orange .wi-cmd-tile-command,
  :global(:root.dark-mode) .wi-cmd-tile--orange .wi-cmd-tile-fn {
    color: #191919;
  }

  :global(:root.dark-mode) .wi-endpoint--success {
    background: rgba(152, 201, 151, 0.08);
    border-color: rgba(152, 201, 151, 0.35);
  }

  :global(:root.dark-mode) .wi-endpoint--success .wi-endpoint-icon {
    color: #98C997;
  }

  :global(:root.dark-mode) .wi-endpoint--success .wi-endpoint-label {
    color: #98C997;
  }

  :global(:root.dark-mode) .wi-connector-path {
    opacity: 0.55;
  }

  :global(:root.dark-mode) .wi-connector-dash {
    opacity: 0.25;
  }

  /* Dark mode chevron glow */
  :global(:root.dark-mode) .wi-connector--1 .wi-chevron { filter: drop-shadow(0 0 5px rgba(255, 183, 122, 0.6)); }
  :global(:root.dark-mode) .wi-connector--2 .wi-chevron { filter: drop-shadow(0 0 5px rgba(107, 155, 94, 0.6)); }
  :global(:root.dark-mode) .wi-connector--3 .wi-chevron { filter: drop-shadow(0 0 5px rgba(255, 128, 18, 0.6)); }
  :global(:root.dark-mode) .wi-connector--4 .wi-chevron { filter: drop-shadow(0 0 5px rgba(255, 183, 122, 0.6)); }
  :global(:root.dark-mode) .wi-connector--5 .wi-chevron { filter: drop-shadow(0 0 5px rgba(107, 155, 94, 0.6)); }

  :global(:root.dark-mode) .wi-worktree {
    background:
      linear-gradient(
        135deg,
        rgba(152, 201, 151, 0.06) 0%,
        rgba(255, 128, 18, 0.04) 100%
      );
    border-color: var(--t-border);
    box-shadow:
      0 0 0 1px rgba(152, 201, 151, 0.06),
      0 4px 24px -4px rgba(0, 0, 0, 0.3);
  }

  :global(:root.dark-mode) .wi-worktree-border rect {
    stroke: rgba(152, 201, 151, 0.35);
  }

  :global(:root.dark-mode) .wi-worktree-label {
    color: #98C997;
    background: var(--t-surface);
    border-color: rgba(152, 201, 151, 0.2);
  }

  :global(:root.dark-mode) .wi-cmd-tile--loop {
    background: rgba(255, 128, 18, 0.12);
    border-color: rgba(255, 128, 18, 0.4);
  }

  /* Pause animations for users who prefer reduced motion */
  @media (prefers-reduced-motion: reduce) {
    .wi-connector-dash,
    .wi-chevron,
    .wi-worktree-border rect {
      animation: none;
    }
  }
</style>

