import '../styles/global.css';
import Analytics from '@vercel/analytics/astro';
import Button from '../components/Button.astro';
import Footer from '../components/Footer.astro';

const siteTitle = "Page Not Found - Sequant";
const siteDescription = "The page you're looking for doesn't exist.";
const siteUrl = "https://sequant.io";
---

<!DOCTYPE html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <link rel="icon" type="image/png" href="/icon2.png" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <meta name="generator" content={Astro.generator} />

    <!-- SEO Meta Tags -->
    <title>{siteTitle}</title>
    <meta name="description" content={siteDescription} />
    <meta name="robots" content="noindex, follow" />

    <!-- Open Graph / Social -->
    <meta property="og:type" content="website" />
    <meta property="og:url" content={siteUrl} />
    <meta property="og:title" content={siteTitle} />
    <meta property="og:description" content={siteDescription} />

    <!-- Google Fonts -->
    <link rel="preconnect" href="https://fonts.googleapis.com" />
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />
    <link rel="stylesheet" href="https://fonts.googleapis.com/css2?family=Roboto:wght@300;400;500&family=Roboto+Mono:wght@400;500&display=swap" />

    <!-- Theme init — must run synchronously before paint to prevent FOUC -->
    <script is:inline>
      (function() {
        var saved = localStorage.getItem('sequant-theme');
        var prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
        if (saved === 'dark' || (!saved && prefersDark)) {
          document.documentElement.classList.add('dark-mode');
        }
      })();
    </script>

  </head>
  <body class="page-404">
    <main class="error-main" id="main-content">
      <div class="error-content">
        <span class="error-tagline">Page Not Found</span>
        <h1 class="error-code">404</h1>
        <p class="error-message">The page you're looking for doesn't exist or has been moved.</p>
        <div class="error-actions">
          <Button href="/" variant="primary" size="lg">Back to Home</Button>
          <Button href="/docs/" variant="ghost" size="lg">View Docs</Button>
        </div>
      </div>
    </main>

    <Footer />
    <Analytics />
  </body>
</html>

<style>
  .page-404 {
    display: flex;
    flex-direction: column;
    min-height: 100vh;
  }

  .error-main {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: var(--space-3xl) var(--side-spacing);
    background-color: var(--t-mint-bg);
  }

  .error-content {
    text-align: center;
    max-width: 600px;
  }

  .error-tagline {
    display: block;
    font-family: var(--font-sans);
    font-weight: var(--font-weight-medium);
    font-size: var(--font-size-sm);
    letter-spacing: var(--letter-spacing-tight);
    text-transform: uppercase;
    color: var(--color-primary);
    margin-bottom: var(--space-md);
  }

  .error-code {
    font-family: var(--font-sans);
    font-weight: var(--font-weight-light);
    font-size: var(--font-size-display);
    line-height: 1;
    letter-spacing: var(--letter-spacing-tight);
    color: var(--t-mint-text);
    margin: 0 0 var(--space-lg);
  }

  .error-message {
